{"file_path":"/home/user/workspace/app/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/app/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  await addPost(title, content);

  // Invalidate the "posts" cache tag so the next request re-fetches fresh data.
  revalidateTag('posts');

  // Redirect to the home page, forcing a full server-side re-render
  // that will execute getCachedPosts() fresh (cache was just invalidated).
  redirect('/');
}
"}

