{"file_path":"/home/user/workspace/app/page.tsx","content":"import { unstable_cache } from 'next/cache';
import { getPosts } from '@/app/lib/posts';
import { PostForm } from '@/app/post-form';

const getCachedPosts = unstable_cache(
  async () => getPosts(),
  ['posts-list'],
  { tags: ['posts'] },
);

export default async function Home() {
  const posts = await getCachedPosts();

  return (
    <main>
      <h1>Posts</h1>

      <PostForm />

      <h2>All Posts</h2>

      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul>
          {posts.map((post) => (
            <li key={post.id}>
              <h3>{post.title}</h3>
              <p>{post.content}</p>
              <small>{post.createdAt.toLocaleDateString()}</small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}
"}

